tlDataChunk*
tlWBLocatorChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case SRR2::ChunkID::TRIGGER_VOLUME:
        dch = new tlWBTriggerVolumeChunk(&ch);
        break;
    case SRR2::ChunkID::SPLINE:
        dch = new tlWBSplineChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

